import { policy } from './policy.js'
import { store, type LedgerEntry } from './store.js'

export function recordDeposit(account: string, amount: number): LedgerEntry {
  policy.assertWithinLimit(account, amount)
  const entry = store.append(account, amount, 'deposit')
  policy.recordActivity(account)
  return entry
}

import { describe, expect, it } from 'vitest'

import { recordDeposit, recordWithdrawal } from './ledger.js'

describe('ledger', () => {
  it('records a deposit entry', () => {
    expect(recordDeposit('alice', 100)).toEqual({
      account: 'alice',
      amount: 100,
      kind: 'deposit',
    })
  })

  it('records a withdrawal as a negative entry', () => {
    expect(recordWithdrawal('bob', 40)).toEqual({
      account: 'bob',
      amount: -40,
      kind: 'withdrawal',
    })
  })
})

import { policy } from './policy.js'
import { store, type LedgerEntry } from './store.js'

export function recordDeposit(account: string, amount: number): LedgerEntry {
  policy.assertWithinLimit(account, amount)
  const entry = store.append(account, amount, 'deposit')
  policy.recordActivity(account)
  return entry
}

export function recordWithdrawal(account: string, amount: number): LedgerEntry {
  policy.assertWithinLimit(account, amount)
  const entry = store.append(account, -amount, 'withdrawal')
  policy.recordActivity(account)
  return entry
}
